-- =============================================================
-- Demo reviews seed (published) — MEMI Abbigliamento
-- Run AFTER the product catalog exists (products FK), e.g.:
--   docker exec -i <mysql-container> mysql -uroot -p<root_pw> memi_db < seed-reviews.sql
-- Idempotent-ish: deletes previous demo rows (by the demo email domain)
-- before inserting, so re-running never duplicates.
-- =============================================================
USE memi_db;

DELETE FROM reviews WHERE customer_email LIKE '%@demo.memi.it';

